	{
		_sche_lock.acquire();
		int prio = lowest_proc_prio;
		for ( pm::Pcb &p : pm::k_proc_pool )
		{
			if ( p._priority < prio && p._state == pm::ProcState::runnable )
			{
				prio = p._priority;
			}
		}
		_sche_lock.release();
		return prio;
	}

